class Solution:
    def areSimilar(self, mat, k):
        original = [row[:] for row in mat]
        cur = [row[:] for row in mat]
        for _ in range(k):
            nxt = []
            for r, row in enumerate(cur):
                if r % 2 == 0:
                    nxt.append(row[1:] + row[:1])
                else:
                    nxt.append(row[-1:] + row[:-1])
            cur = nxt
        return cur == original

