class Solution:
    def areSimilar(self, mat, k):
        for r, row in enumerate(mat):
            n = len(row)
            s = k % n
            if s == 0:
                continue
            if r % 2 == 0:
                rotated = row[s:] + row[:s]
            else:
                rotated = row[-s:] + row[:-s]
            if rotated != row:
                return False
        return True

