var areSimilar = function(mat, k) {
    for (let r = 0; r < mat.length; r++) {
        const row = mat[r];
        const n = row.length;
        const s = k % n;
        if (s === 0) continue;
        let rotated;
        if (r % 2 === 0) {
            rotated = row.slice(s).concat(row.slice(0, s));
        } else {
            rotated = row.slice(n - s).concat(row.slice(0, n - s));
        }
        for (let i = 0; i < n; i++) {
            if (rotated[i] !== row[i]) return false;
        }
    }
    return true;
};
